const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401, error: 'Missing session token' } };
const required = ['advisor_id','carrier_name','effective_date','commission_split_carrier','commission_split_mga','commission_split_advisor'];
for (const f of required) { if (body[f] == null) return { json: { _empty: true, status: 400, error: f + ' required' } }; }
const sumPct = (parseFloat(body.commission_split_carrier) || 0) + (parseFloat(body.commission_split_mga) || 0) + (parseFloat(body.commission_split_advisor) || 0);
if (Math.abs(sumPct - 100.0) > 0.01) return { json: { _empty: true, status: 400, error: 'Commission splits must sum to 100 (got ' + sumPct + ')' } };
return { json: { token: token, advisor_id: body.advisor_id, carrier_name: body.carrier_name, carrier_appointment_number: body.carrier_appointment_number || null, product_lines: Array.isArray(body.product_lines) ? body.product_lines : [], effective_date: body.effective_date, expires_date: body.expires_date || null, commission_split_carrier: body.commission_split_carrier, commission_split_mga: body.commission_split_mga, commission_split_advisor: body.commission_split_advisor, documentation_url: body.documentation_url || null } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401, error: 'Invalid session' } };
if (row.user_role !== 'mga_principal' && row.user_role !== 'admin') return { json: { _unauthorized: true, status: 403, error: 'mga_principal role required' } };
const i = $('Extract + Validate Splits').item.json;
return { json: { _ok: true, mga_principal_id: row.id || row.user_id, advisor_id: i.advisor_id, carrier_name: i.carrier_name, carrier_appointment_number: i.carrier_appointment_number, product_lines: i.product_lines, effective_date: i.effective_date, expires_date: i.expires_date, commission_split_carrier: i.commission_split_carrier, commission_split_mga: i.commission_split_mga, commission_split_advisor: i.commission_split_advisor, documentation_url: i.documentation_url } };
